import React, { useEffect, useState, useMemo } from 'react';
import { useTable, useSortBy, usePagination, useCallback } from 'react-table';
import AddProject from './AddProject'; // Adjust the import path as needed
import EditProject from './EditProject'; // Adjust the import path as needed
import './PurchaseFunc.css';

const ProjectFunc = ({ apiBaseUrl }) => {
  const [editingProject, setEditingProject] = useState(null);
  const [projects, setProjects] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [globalFilter, setGlobalFilter] = useState('');

  // Utility function to fetch data from the API
  const fetchAPI = async (url, options = {}) => {
    try {
      const authToken = sessionStorage.getItem('authToken');
      const response = await fetch(`${apiBaseUrl}${url}`, {
        ...options,
        headers: {
          ...options.headers,
          'Authorization': `Bearer ${authToken}`,
          'Content-Type': 'application/json',
        },
      });
      if (!response.ok) throw new Error('Network response was not ok');
      return response.json();
    } catch (error) {
      console.error('Error fetching data:', error);
    }
  };

  // Fetch data from the API
  const fetchData = async () => {
    setIsLoading(true);
    const data = await fetchAPI('/projectsAPI');
    if (data) setProjects(data);
    setIsLoading(false);
  };

  useEffect(() => {
    fetchData();
  }, []);

  // Function to handle adding a new project
  const handleAddProject = async (newProject) => {
    await fetchAPI('/projectsAPI', {
      method: 'POST',
      body: JSON.stringify(newProject),
    });
    fetchData();
  };

  // Function to handle deleting a project
  const handleDeleteProject = async (projectId) => {
    if (window.confirm('Are you sure you want to delete this project?')) {
      await fetchAPI(`/projectsAPI/${projectId}`, {
        method: 'DELETE',
      });
      fetchData();
    }
  };

  // Function to toggle the status of a project (0 for in progress, 1 for completed)
  const handleToggleProjectStatus = async (project) => {
    const updatedProject = { ...project, status: project.status === 1 ? 0 : 1 };
    await fetchAPI(`/projectsAPI/${project.prid}`, {
      method: 'PUT',
      body: JSON.stringify(updatedProject),
    });
    fetchData();
  };

  const openProjectOutflowTable = useCallback((projectId) => {
    window.open(`/ProjectOutflows?projectId=${projectId}`, '_blank');
  }, []);

  const columns = useMemo(
    () => [
      { Header: 'ID', accessor: 'prid' },
      {
        Header: 'Name',
        accessor: 'name',
        Cell: ({ row }) => {
          const projectOutflows = outflows.filter((outflow) => outflow.project === row.original.prid);
          return (
            <span
              title={projectOutflows.length > 0 ? projectOutflows.map((outflow) => `Outflow ID: ${outflow.outflowid} Material ID:${outflow.materialid} Quantity: ${outflow.quantity}`).join('\n') : 'No outflows for this project'}
              style={{ cursor: 'pointer', color: 'blue', textDecoration: 'underline' }}
              onClick={() => openProjectOutflowTable(row.original.prid)}
            >
              {row.original.name}
            </span>
          );
        }
      },
      { Header: 'Description', accessor: 'description' },
      { Header: 'Projected Material Cost', accessor: 'prmatcost' },
      { Header: 'Projected Labor Cost', accessor: 'prlabcost' },
      { Header: 'Sale', accessor: 'sale' },
      {
        Header: 'Real Material Cost',
        accessor: 'realmatcostNumeric', // Use the numeric value for sorting
        Cell: ({ row }) => {
          // Check if realmatcostNumeric is defined
          if (typeof row.original.realmatcostNumeric === 'number') {
            const formattedCost = `${row.original.realmatcostNumeric.toFixed(2)} €`; // Format for display
            return formattedCost;
          }
          return 'N/A'; // Return 'N/A' or some placeholder if undefined
        },
        sortType: 'basic' // Default sorting should work fine now
      }


      ,


      { Header: 'Real Labor Cost', accessor: 'reallabcost' },
      { Header: 'Total Cost', accessor: 'totalcost' },
      {
        Header: 'Status',
        accessor: 'status',
        Cell: ({ row }) => {
          const statusValue = row.original.status.data[0];
          return (
            <label>
              Completed:
              <input
                type="checkbox"
                checked={statusValue === 1}
                onChange={() => handleUpdate(row.original, statusValue === 1 ? 0 : 1)}
              />
            </label>
          );
        },
      },
      {
        Header: 'Actions',
        accessor: 'actions',
        Cell: ({ row }) => (
          <div>
            <button onClick={() => handleEdit(row.original)}>Edit</button>
            <button onClick={() => handleDelete(row.original)}>Delete</button>
          </div>
        ),
      },
    ],
    [handleEdit, handleDelete, outflows, handleUpdate, openProjectOutflowTable]
  );

  const tableInstanceInProgress = useTable(
    {
      columns,
      data: projects.filter((project) => project.status === 0),
    },
    useSortBy,
    usePagination
  );

  const tableInstanceCompleted = useTable(
    {
      columns,
      data: projects.filter((project) => project.status === 1),
    },
    useSortBy,
    usePagination
  );

  return (
    <div className='container'>
      <AddProject onAddProject={handleAddProject} />
      <input
        type="text"
        value={globalFilter}
        onChange={(e) => setGlobalFilter(e.target.value)}
        placeholder="Search projects..."
      />
      <h2>Projects In Progress</h2>
      <table {...tableInstanceInProgress.getTableProps()}>
        {/* Render the table */}
      </table>
      <h2>Projects Completed</h2>
      <table {...tableInstanceCompleted.getTableProps()}>
        {/* Render the table */}
      </table>
      {editingProject && (
        <EditProject project={editingProject} onUpdateProject={handleUpdateProject} onCancel={() => setEditingProject(null)} />
      )}
    </div>
  );
};

export default ProjectFunc;
